import { useState } from 'react';
import { Briefcase, BookOpen, Building2, GraduationCap, Globe, Landmark, FlameKindling, Award } from 'lucide-react';
import SectionHeader from './SectionHeader';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';

// Org icon mapping
function OrgIcon({ org, type }) {
  const cls = "w-5 h-5";
  if (org.includes('CIB') && type === 'internship') return <Landmark className={cls} />;
  if (org.includes('ASORC') || org.includes('Refining') || org.includes('تكرير')) return <FlameKindling className={cls} />;
  if (org.includes('Nile') || org.includes('النيل')) return <FlameKindling className={cls} />;
  if (org.includes('CIB') && type === 'training') return <Landmark className={cls} />;
  if (org.includes('Google') || org.includes('Misr') || org.includes('مصر')) return <Globe className={cls} />;
  if (org.includes('HSBC')) return <Building2 className={cls} />;
  if (type === 'internship') return <Briefcase className={cls} />;
  return <GraduationCap className={cls} />;
}

export default function Experience() {
  const { dark, lang } = useApp();
  const tr = t[lang];
  const [filter, setFilter] = useState('all');

  const internships = tr.experiences.filter(e => e.type === 'internship');
  const trainings   = tr.experiences.filter(e => e.type === 'training');
  const filtered    = filter === 'all'
    ? tr.experiences
    : filter === 'internship' ? internships : trainings;

  const bg      = dark ? 'bg-[#0f0f14]'  : 'bg-cream';
  const cardBg  = dark ? 'bg-[#13131e]'  : 'bg-parchment';
  const border  = dark ? 'border-white/8' : 'border-ink/8';
  const tBase   = dark ? 'text-white'     : 'text-ink2';
  const tMuted  = dark ? 'text-white/50'  : 'text-muted';
  const tMuted2 = dark ? 'text-white/65'  : 'text-muted2';
  const iconBg  = dark ? 'bg-white/5'     : 'bg-cream';

  const filterActive   = dark ? 'bg-white text-[#0f0f14]'   : 'bg-ink text-parchment';
  const filterInactive = dark ? 'bg-white/5 text-white/50 border-white/10 hover:text-white'
                               : 'bg-parchment text-muted2 border-ink/10 hover:text-ink';

  return (
    <section id="experience" className={`py-24 px-[5%] ${bg} transition-colors duration-300`}>
      <SectionHeader tag={tr.expTag} title={tr.expTitle} />

      {/* Filter tabs */}
      <div className="flex gap-2 mb-10 flex-wrap">
        {[['all', tr.all], ['internship', tr.internships], ['training', tr.training]].map(([val, label]) => (
          <button key={val} onClick={() => setFilter(val)}
            className={`px-4 py-1.5 rounded-full text-sm font-medium transition-all border ${filter === val ? filterActive : filterInactive}`}>
            {label}
            <span className={`ml-1.5 text-xs opacity-60`}>
              ({val === 'all' ? tr.experiences.length : val === 'internship' ? internships.length : trainings.length})
            </span>
          </button>
        ))}
      </div>

      {/* Cards grid */}
      <div className="grid md:grid-cols-2 gap-4">
        {filtered.map((e, i) => (
          <div key={`${filter}-${i}`}
            className={`${cardBg} rounded-2xl border ${border} transition-all duration-300 hover:-translate-y-1 hover:shadow-lg overflow-hidden`}
            style={{ animation: `fadeUp .4s ${i * 0.06}s ease both` }}>

            {/* Card header strip */}
            <div className={`h-1 w-full ${e.type === 'internship' ? 'bg-gradient-to-r from-amber to-amber2' : 'bg-gradient-to-r from-teal to-teal2'}`} />

            <div className="p-5">
              {/* Top row */}
              <div className="flex items-start gap-3">
                {/* Icon */}
                <div className={`w-10 h-10 rounded-xl ${iconBg} border ${border} flex items-center justify-center flex-shrink-0 ${e.type === 'internship' ? 'text-amber' : 'text-teal'}`}>
                  <OrgIcon org={e.org} type={e.type} />
                </div>

                <div className="flex-1 min-w-0">
                  {/* Badge + date */}
                  <div className="flex items-center gap-2 mb-1 flex-wrap">
                    <span className={`inline-flex items-center gap-1 text-[.6rem] font-semibold tracking-wider uppercase px-2 py-0.5 rounded-full ${
                      e.type === 'internship' ? 'bg-amber/10 text-amber2' : 'bg-teal/10 text-teal2'
                    }`}>
                      {e.type === 'internship'
                        ? <><Briefcase size={9} /> {tr.internship}</>
                        : <><BookOpen size={9} /> {tr.training}</>
                      }
                    </span>
                    <span className={`text-[.65rem] font-medium ${tMuted}`}>{e.date}</span>
                  </div>

                  {/* Role */}
                  <h3 className={`font-semibold text-[.95rem] leading-tight ${tBase}`}>{e.role}</h3>
                  {/* Org + location */}
                  <p className={`text-[.78rem] mt-0.5 ${tMuted}`}>{e.org} · {e.location}</p>
                </div>
              </div>

              {/* Description */}
              <div className={`mt-3 pt-3 border-t ${border}`}>
                {e.type === 'training' && e.desc.includes('·') ? (
                  /* Training with multiple topics — show as tags */
                  <div className="flex flex-wrap gap-1.5">
                    {e.desc.split('·').map((item, idx) => (
                      <span key={idx} className={`text-[.72rem] px-2.5 py-1 rounded-lg border ${border} ${tMuted2} bg-transparent`}>
                        {item.trim()}
                      </span>
                    ))}
                  </div>
                ) : (
                  <p className={`text-[.85rem] leading-[1.7] ${tMuted2}`}>{e.desc}</p>
                )}
              </div>

              {/* Cert image link if available */}
              {e.certImg && (
                <button
                  onClick={() => window.open(e.certImg, '_blank')}
                  className={`mt-3 flex items-center gap-1.5 text-[.72rem] font-medium text-amber hover:text-amber2 transition-colors`}>
                  <Award size={13} />
                  {lang === 'ar' ? 'عرض الشهادة' : 'View Certificate'}
                </button>
              )}
            </div>
          </div>
        ))}
      </div>
    </section>
  );
}
